import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyAUGH515dj40sGUUHe2iK327fb1yP-_UG8",
  authDomain: "atedimento-normatel.firebaseapp.com",
  projectId: "atedimento-normatel",
  storageBucket: "atedimento-normatel.firebasestorage.app",
  messagingSenderId: "284942469214",
  appId: "1:284942469214:web:cfa8879fcedf309b888ccf",
  measurementId: "G-WCS1347YC1"
};

const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);

import { db } from './firebase';
import { 
  collection, 
  query, 
  where, 
  getDocs, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  setDoc,
  Timestamp,
  orderBy
} from "firebase/firestore";
import { Ticket, User } from '../types';

class DataService {
  // Converte Timestamps do Firestore para datas JS para manter compatibilidade com o app
  private static parseFirestoreData(data: any): any {
    const parsed = { ...data };
    Object.keys(parsed).forEach(key => {
      if (parsed[key] instanceof Timestamp) {
        parsed[key] = parsed[key].toDate();
      }
    });
    return parsed;
  }

  // --- TICKETS ---

  static async getTickets(date: string): Promise<Ticket[]> {
    try {
      const q = query(
        collection(db, "tickets"), 
        where("sessionDate", "==", date),
        orderBy("arrivalTime", "asc")
      );
      const querySnapshot = await getDocs(q);
      const tickets: Ticket[] = [];
      querySnapshot.forEach((doc) => {
        tickets.push({ id: doc.id, ...this.parseFirestoreData(doc.data()) } as Ticket);
      });
      return tickets;
    } catch (e) {
      console.error("Erro ao buscar tickets no Firestore:", e);
      return [];
    }
  }

  static async addTicket(date: string, ticket: Omit<Ticket, 'id'>): Promise<void> {
    try {
      await addDoc(collection(db, "tickets"), {
        ...ticket,
        sessionDate: date,
        arrivalTime: Timestamp.now()
      });
    } catch (e) {
      console.error("Erro ao adicionar ticket:", e);
    }
  }

  static async updateTicket(date: string, updatedTicket: Ticket): Promise<void> {
    try {
      const { id, ...data } = updatedTicket;
      const ticketRef = doc(db, "tickets", id);

      // Converter datas para Timestamps antes de salvar
      const payload: any = { ...data };
      Object.keys(payload).forEach(key => {
        if (payload[key] instanceof Date) {
          payload[key] = Timestamp.fromDate(payload[key]);
        }
      });

      await updateDoc(ticketRef, payload);
    } catch (e) {
      console.error("Erro ao atualizar ticket:", e);
    }
  }

  static async deleteTicket(date: string, ticketId: string): Promise<void> {
    try {
      await deleteDoc(doc(db, "tickets", ticketId));
    } catch (e) {
      console.error("Erro ao deletar ticket:", e);
    }
  }

  // --- USUÁRIOS ---

  static async getUsers(): Promise<User[]> {
    try {
      const querySnapshot = await getDocs(collection(db, "users"));
      const users: User[] = [];
      querySnapshot.forEach((doc) => {
        users.push({ id: doc.id, ...doc.data() } as User);
      });
      return users;
    } catch (e) {
      console.error("Erro ao buscar usuários:", e);
      return [];
    }
  }

  static async saveUser(user: User): Promise<void> {
    try {
      const { id, ...data } = user;
      await setDoc(doc(db, "users", id), data);
    } catch (e) {
      console.error("Erro ao salvar usuário:", e);
    }
  }

  static async deleteUser(id: string): Promise<void> {
    try {
      await deleteDoc(doc(db, "users", id));
    } catch (e) {
      console.error("Erro ao remover usuário:", e);
    }
  }
}

export default DataService;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { LOGO_URL } from '../constants';
import DataService from '../services/dataService';

interface LoginScreenProps {
  onLogin: (user: User) => void;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const seedAdmin = async () => {
      const users = await DataService.getUsers();
      const masterAdminExists = users.find(u => u.username === 'DIEGO.SILVA');

      if (!masterAdminExists) {
        const masterAdmin: User = { 
          id: 'master-admin-01', 
          username: 'DIEGO.SILVA', 
          password: '05171888302', 
          role: 'admin', 
          name: 'DIEGO SILVA (ADMIN)' 
        };
        await DataService.saveUser(masterAdmin);
      }
    };
    seedAdmin();
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      const users = await DataService.getUsers();
      const user = users.find(u => u.username.toUpperCase() === username.toUpperCase() && u.password === password);

      if (user) {
        onLogin(user);
      } else {
        setError('Usuário ou senha inválidos. Verifique as credenciais.');
      }
    } catch (err) {
      setError('Erro de conexão com o banco de dados.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#1a1a1a] flex items-center justify-center p-6 font-sans">
      <div className="max-w-md w-full bg-[#2a2a2a] rounded-3xl p-8 border border-[#3a3a3a] shadow-2xl animate-fadeIn">
        <div className="text-center mb-10">
          <div className="inline-block bg-white p-3 rounded-2xl mb-6 shadow-xl border-2 border-[#e67324]">
            <img src={LOGO_URL} alt="Normatel Logo" className="max-w-[100px] h-auto object-contain" />
          </div>
          <h1 className="text-2xl font-black text-white tracking-tighter uppercase leading-none">
            SISTEMA DE GESTÃO <br/><span className="text-[#e67324] text-lg uppercase tracking-widest font-bold">Logística e Vendas</span>
          </h1>
          <div className="h-1 w-12 bg-[#e67324] mx-auto mt-4 rounded-full"></div>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-[#e67324] text-[10px] font-black uppercase tracking-widest mb-2 ml-1">Usuário</label>
            <div className="relative group">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-[#e67324] transition-colors">
                <i className="fas fa-user-circle"></i>
              </span>
              <input 
                type="text" 
                required
                disabled={isLoading}
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-[#1a1a1a] border border-[#3a3a3a] text-white p-4 pl-12 rounded-xl focus:ring-2 focus:ring-[#e67324] focus:border-transparent outline-none font-bold uppercase transition-all disabled:opacity-50"
                placeholder="USUÁRIO"
              />
            </div>
          </div>

          <div>
            <label className="block text-[#e67324] text-[10px] font-black uppercase tracking-widest mb-2 ml-1">Senha</label>
            <div className="relative group">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-[#e67324] transition-colors">
                <i className="fas fa-lock"></i>
              </span>
              <input 
                type="password" 
                required
                disabled={isLoading}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-[#1a1a1a] border border-[#3a3a3a] text-white p-4 pl-12 rounded-xl focus:ring-2 focus:ring-[#e67324] focus:border-transparent outline-none font-bold transition-all disabled:opacity-50"
                placeholder="••••••••"
              />
            </div>
          </div>

          {error && (
            <div className="bg-red-500/10 border border-red-500/50 p-4 rounded-xl text-red-400 text-xs font-bold text-center animate-bounce">
              <i className="fas fa-exclamation-triangle mr-2"></i> {error}
            </div>
          )}

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full bg-[#e67324] hover:bg-orange-500 text-white font-black py-5 rounded-xl shadow-2xl transition-all active:scale-[0.97] uppercase tracking-widest text-sm border-b-4 border-orange-700 flex items-center justify-center gap-3 disabled:opacity-50"
          >
            {isLoading ? <i className="fas fa-spinner fa-spin"></i> : 'ENTRAR NO SISTEMA'}
          </button>
        </form>

        <div className="mt-10 pt-6 border-t border-[#3a3a3a] text-center">
            <p className="text-gray-500 text-[9px] uppercase font-black tracking-widest">
              Conectado ao Firebase Cloud • Segurança Ativa
            </p>
        </div>
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useEffect } from 'react';
import { User, UserRole } from '../types';
import DataService from '../services/dataService';

const UserManagement: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    username: '',
    password: '',
    role: 'staff' as UserRole
  });

  const loadUsers = async () => {
    setIsLoading(true);
    const data = await DataService.getUsers();
    setUsers(data);
    setIsLoading(false);
  };

  useEffect(() => {
    loadUsers();
  }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.username || !formData.password) return;

    const formattedUsername = formData.username.toUpperCase().trim();

    if (users.find(u => u.username.toUpperCase() === formattedUsername)) {
      alert('Este nome de usuário já está em uso no sistema.');
      return;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: formData.name.trim(),
      username: formattedUsername,
      password: formData.password,
      role: formData.role
    };

    setIsLoading(true);
    await DataService.saveUser(newUser);
    await loadUsers();
    setFormData({ name: '', username: '', password: '', role: 'staff' });
    alert('Usuário cadastrado com sucesso!');
  };

  const removeUser = async (id: string, username: string) => {
    if (username === 'DIEGO.SILVA') {
      alert('ERRO: O Administrador Master não pode ser removido do sistema.');
      return;
    }

    if (confirm(`ATENÇÃO: Deseja realmente revogar o acesso de ${username}?`)) {
      setIsLoading(true);
      await DataService.deleteUser(id);
      await loadUsers();
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fadeIn">
      <div className="lg:col-span-1 bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
        <div className="flex items-center gap-3 mb-8">
          <div className="bg-orange-50 text-[#e67324] p-3 rounded-xl">
             <i className="fas fa-user-plus text-xl"></i>
          </div>
          <div>
            <h2 className="text-xl font-black tracking-tight leading-none">NOVO ACESSO</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">Firestore Backend</p>
          </div>
        </div>

        <form onSubmit={handleAdd} className="space-y-5">
          <div>
            <label className="text-[10px] font-black uppercase text-gray-400 ml-1">Nome Completo</label>
            <input required placeholder="Ex: João Ferreira" className="w-full p-4 bg-gray-50 border-2 border-transparent rounded-2xl outline-none focus:border-[#e67324] font-bold transition-all" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-gray-400 ml-1">Usuário de Login</label>
            <input required placeholder="USUARIO.NOME" className="w-full p-4 bg-gray-50 border-2 border-transparent rounded-2xl outline-none focus:border-[#e67324] font-bold uppercase transition-all" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} />
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-gray-400 ml-1">Senha</label>
            <input required type="password" placeholder="••••••••" className="w-full p-4 bg-gray-50 border-2 border-transparent rounded-2xl outline-none focus:border-[#e67324] font-bold transition-all" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-gray-400 ml-1">Perfil</label>
            <select className="w-full p-4 bg-gray-50 border-2 border-transparent rounded-2xl outline-none focus:border-[#e67324] font-bold cursor-pointer transition-all" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as UserRole})}>
              <option value="staff">OPERADOR</option>
              <option value="admin">ADMINISTRADOR</option>
            </select>
          </div>
          <button type="submit" disabled={isLoading} className="w-full bg-[#1a1a1a] hover:bg-[#e67324] text-white py-5 rounded-2xl font-black uppercase text-xs tracking-widest mt-4 transition-all shadow-lg active:scale-95 disabled:opacity-50">
            {isLoading ? <i className="fas fa-spinner fa-spin"></i> : 'CADASTRAR ACESSO'}
          </button>
        </form>
      </div>

      <div className="lg:col-span-2 bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden flex flex-col">
        <div className="p-8 border-b bg-gray-50/50">
          <h2 className="text-xl font-black uppercase tracking-tighter">Colaboradores no Firestore</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase mt-1">Sincronização em Tempo Real</p>
        </div>

        <div className="overflow-x-auto flex-1">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-[#1a1a1a] text-[10px] font-black uppercase text-white">
                <th className="px-8 py-5">Nome</th>
                <th className="px-8 py-5">Usuário</th>
                <th className="px-8 py-5 text-center">Perfil</th>
                <th className="px-8 py-5 text-right">Controle</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {users.map(u => (
                <tr key={u.id} className="hover:bg-orange-50/30 transition-colors group">
                  <td className="px-8 py-5 font-bold text-gray-800">{u.name}</td>
                  <td className="px-8 py-5 text-gray-500 font-mono text-xs">{u.username}</td>
                  <td className="px-8 py-5 text-center">
                    <span className={`text-[9px] font-black px-4 py-1.5 rounded-full uppercase ${u.role === 'admin' ? 'bg-[#1a1a1a] text-[#e67324]' : 'bg-gray-100 text-gray-500'}`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    {u.username !== 'DIEGO.SILVA' && (
                      <button onClick={() => removeUser(u.id!, u.username)} className="w-10 h-10 rounded-xl bg-red-50 text-red-400 hover:bg-red-500 hover:text-white transition-all flex items-center justify-center ml-auto">
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default UserManagement;

{
  "name": "normatel-gestao-atendimento",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview"
