import { Ticket, User } from '../types';

class DataService {
  private static getStorageKey(date: string) {
    return `normatel_tickets_${date}`;
  }

  // --- TICKETS ---

  static async getTickets(date: string): Promise<Ticket[]> {
    const data = localStorage.getItem(this.getStorageKey(date));
    if (!data) return [];
    try {
      return JSON.parse(data);
    } catch (e) {
      return [];
    }
  }

  static async addTicket(date: string, ticket: Ticket): Promise<void> {
    const tickets = await this.getTickets(date);
    tickets.push(ticket);
    localStorage.setItem(this.getStorageKey(date), JSON.stringify(tickets));
  }

  static async updateTicket(date: string, updatedTicket: Ticket): Promise<void> {
    const tickets = await this.getTickets(date);
    const index = tickets.findIndex(t => t.id === updatedTicket.id);
    if (index !== -1) {
      tickets[index] = updatedTicket;
      localStorage.setItem(this.getStorageKey(date), JSON.stringify(tickets));
    }
  }

  static async deleteTicket(date: string, ticketId: string): Promise<void> {
    const tickets = await this.getTickets(date);
    const filtered = tickets.filter(t => t.id !== ticketId);
    localStorage.setItem(this.getStorageKey(date), JSON.stringify(filtered));
  }

  // --- USUÁRIOS ---

  static async getUsers(): Promise<User[]> {
    const data = localStorage.getItem('normatel_users');
    if (!data) return [];
    try {
      return JSON.parse(data);
    } catch (e) {
      return [];
    }
  }

  static async saveUser(user: User): Promise<void> {
    const users = await this.getUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index !== -1) {
      users[index] = user;
    } else {
      users.push(user);
    }
    localStorage.setItem('normatel_users', JSON.stringify(users));
  }

  static async deleteUser(id: string): Promise<void> {
    const users = await this.getUsers();
    const filtered = users.filter(u => u.id !== id);
    localStorage.setItem('normatel_users', JSON.stringify(filtered));
  }
}

export default DataService;

